nta.declaration:
/* ---- Priority levels (lower number = higher priority, Buttazzo §7.3) ---- */
const int PMAX = 9;          /* infinity sentinel */
const int P1   = 1;          /* tau1 nominal priority */
const int P2   = 2;          /* tau2 nominal priority */
const int P3   = 3;          /* tau3 nominal priority */

/* ---- Number of tasks ---- */
const int N = 3;

/* ---- Active priority array: act_prio[i] is tau(i+1)'s current priority ---- */
int[1,9] act_prio[N];        /* act_prio[0]=tau1, [1]=tau2, [2]=tau3 */

/* ---- Semaphore (binary): holder = task index (0/1/2), -1 if free ---- */
int[-1,2] holder;            /* who holds S_R (-1 = free) */

/* ---- Blocking duration counters (integer approximation) ---- */
int[0,20] block_dur[N];     /* how long each task has been blocked this instance */

/* ---- Observer flags ---- */
bool blocking_tau1;          /* tau1 currently blocked on S_R */
bool blocked_tau2;           /* tau2 currently blocked (push-through) */

/* ---- Synchronisation channels ---- */
/* lock_req[i]! : task i requests lock on S_R     */
/* lock_ack[i]! : resource manager grants lock    */
/* unlock[i]!   : task i releases S_R             */
/* boost[i]!    : priority manager boosts task i  */
/* restore[i]!  : priority manager restores task i*/
chan lock_req[N];
chan lock_ack[N];
chan unlock_rel[N];
chan boost[N];
chan restore_prio[N];
chan sched_event;            /* any priority change -> re-evaluate scheduler */

/* ---- Helper: ceiling of S_R = P1 (used by tau1 and tau3, max prio = P1) ---- */
const int CEILING_SR = P1;

/* ---- PIP inheritance function (Buttazzo Eq 7.8) ---- */
/* Implemented via the ResourceManager automaton transitions */

template.parameter:
const int id, const int nom, const int C,
               const int T_period, const int D_deadline,
               const int uses_R, const int cs_len

template.declaration:
/* queued: which tasks are waiting (bit mask) */
int[0,7] wait_mask;
int[-1,2] pending_id;   /* task requesting the lock */

nta.system:
/* Task instantiation:
   Task(id, nom_prio, C, T, D, uses_R, cs_len)          */
tau1 = Task(0, 1, 1,  4,  4, 1, 1);   /* uses R, CS len=1  */
tau2 = Task(1, 2, 2,  6,  6, 0, 0);   /* no R              */
tau3 = Task(2, 3, 4, 16, 16, 1, 4);   /* uses R, CS len=4  */

rm   = ResourceManager();
obs  = Observer();

system tau1, tau2, tau3, rm, obs;
